const input = $input.first().json;
const domain = (input.body?.domain || input.domain || '').trim().toLowerCase();

const domainRegex = /^[a-zA-Z0-9][a-zA-Z0-9-]{0,61}[a-zA-Z0-9]?\.[a-zA-Z]{2,}$/;
if (!domain || !domainRegex.test(domain)) {
  return [{ json: { valid: false, error: 'Invalid domain format' } }];
}

const today = new Date().toISOString().split('T')[0];
return [{ json: { valid: true, domain, idempotency_key: `${domain}_${today}` } }];

const input = $input.first().json;
if (input.error || (input.statusCode && input.statusCode >= 400)) {
  const sc = input.statusCode || 0;
  const retryable = sc === 429 || sc >= 500 || sc === 0;
  return [{ json: { success: false, retryable, error: `${retryable ? 'Transient' : 'Permanent'}: ${sc} - ${input.error || input.message || 'Unknown'}`, data: null } }];
}
try {
  const content = input.choices?.[0]?.message?.content || '';
  const data = JSON.parse(content.replace(/```json\n?|```\n?/g, '').trim());
  return [{ json: { success: true, data } }];
} catch (err) {
  return [{ json: { success: false, retryable: false, error: `Parse error: ${err.message}`, data: null } }];
}

