const company = $('Parse Company Data').first().json;
const techStack = $('Parse Tech Stack').first().json;
const contacts = $('Parse Contacts').first().json;
const jobId = $('Create Job Record').first().json.id;
const domain = $('Validate & Check Idempotency').first().json.domain;

const steps = { company, techStack, contacts };
const succeeded = Object.entries(steps).filter(([k, v]) => v.success);
const failed = Object.entries(steps).filter(([k, v]) => !v.success);

let status = 'completed';
if (succeeded.length === 0) status = 'failed';
else if (failed.length > 0) status = 'partial';

return [{
  json: {
    job_id: jobId, domain, status,
    company_data: company.data,
    tech_stack: techStack.data,
    contacts: contacts.data,
    enrichment_steps: Object.fromEntries(Object.entries(steps).map(([k, v]) => [k, v.success ? 'ok' : v.error])),
    error_log: failed.map(([k, v]) => ({ step: k, error: v.error, retryable: v.retryable }))
  }
}];
